# Tools are just functions that take a string, return a string.
def calc(expr: str) -> str:
    try:
        return str(eval(expr, {"__builtins__": {}}))
    except Exception as e:
        return f"error: {e}"

def search(query: str) -> str:
    # stub; swap for a real search API
    facts = {"nolan birth year": "1970"}
    return facts.get(query.lower(), "no result")

TOOLS = {"calc": calc, "search": search}

def react(question, llm, max_steps=6):
    t = SYSTEM + f"\nQuestion: {question}\n"
    for _ in range(max_steps):
        step = llm(t, stop=["Observation:"])
        t += step
        if "Answer:" in step:
            return step.split("Answer:")[-1].strip()
        name, arg = parse_action(step)
        if name not in TOOLS:
            obs = f"error: unknown tool {name}"
        else:
            obs = TOOLS[name](arg)
        t += f"\nObservation: {obs}\n"
    return "step limit reached"

